import sys
import heapq
from collections import deque

def solve(c: int, connections: list[list[int]], queries: list[list[int]]) -> list[int]:
    # Build adjacency list
    adj = [[] for _ in range(c + 1)]
    for u, v in connections:
        adj[u].append(v)
        adj[v].append(u)

    # Find connected components
    visited = [False] * (c + 1)
    components = []
    for i in range(1, c + 1):
        if not visited[i]:
            q = deque()
            q.append(i)
            visited[i] = True
            component = []
            while q:
                node = q.popleft()
                component.append(node)
                for neighbor in adj[node]:
                    if not visited[neighbor]:
                        visited[neighbor] = True
                        q.append(neighbor)
            components.append(component)

    # Assign component id to each node
    component_id = [0] * (c + 1)
    for comp_id, comp in enumerate(components):
        for node in comp:
            component_id[node] = comp_id

    # Create heaps for each component
    component_heaps = {}
    for comp_id, comp in enumerate(components):
        heap = comp.copy()
        heapq.heapify(heap)
        component_heaps[comp_id] = heap

    # Initialize active array
    active = [True] * (c + 1)

    # Process queries
    res = []
    for q in queries:
        if q[0] == 1:
            x = q[1]
            if active[x]:
                res.append(x)
            else:
                comp_id = component_id[x]
                heap = component_heaps[comp_id]
                # Remove inactive nodes from the top
                while heap and not active[heap[0]]:
                    heapq.heappop(heap)
                if not heap:
                    res.append(-1)
                else:
                    res.append(heap[0])
        else:
            x = q[1]
            active[x] = False

    return res
