from collections import defaultdict
import heapq

def solve(c: int, connections: list[list[int]], queries: list[list[int]]) -> list[int]:
    class DSU:
        def __init__(self, size):
            self.parent = list(range(size + 1))
            self.rank = [1] * (size + 1)

        def find(self, x):
            if self.parent[x] != x:
                self.parent[x] = self.find(self.parent[x])
            return self.parent[x]

        def union(self, x, y):
            x_root = self.find(x)
            y_root = self.find(y)
            if x_root == y_root:
                return
            if self.rank[x_root] < self.rank[y_root]:
                self.parent[x_root] = y_root
            else:
                self.parent[y_root] = x_root
                if self.rank[x_root] == self.rank[y_root]:
                    self.rank[x_root] += 1

    dsu = DSU(c)
    for u, v in connections:
        dsu.union(u, v)

    roots = defaultdict(list)
    for i in range(1, c + 1):
        roots[dsu.find(i)].append(i)

    heap_dict = defaultdict(list)
    for root in roots:
        stations = roots[root]
        heap = []
        for station in stations:
            heapq.heappush(heap, station)
        heap_dict[root] = heap

    online = [True] * (c + 1)
    res = []
    for q in queries:
        if q[0] == 1:
            x = q[1]
            if online[x]:
                res.append(x)
            else:
                root = dsu.find(x)
                while heap_dict[root] and not online[heap_dict[root][0]]:
                    heapq.heappop(heap_dict[root])
                if not heap_dict[root]:
                    res.append(-1)
                else:
                    res.append(heap_dict[root][0])
        else:
            x = q[1]
            online[x] = False
    return res
